<template>
	<div
		class="capacity-grid bg-white rounded-lg border border-gray-200 overflow-x-auto flex-1 -mx-4 sm:mx-0"
	>
		<!-- Loading state -->
		<div v-if="loading" class="p-8 text-center text-gray-500">
			Ładowanie planu zdolności...
		</div>

		<!-- Empty state -->
		<div v-else-if="employees.length === 0" class="p-8 text-center text-gray-500">
			Brak pracowników do wyświetlenia
		</div>

		<!-- Grid table -->
		<div v-else :style="{ minWidth: minGridWidth }">
			<!-- Header row: Pracownik | Pon | Wt | Śr | Czw | Pt | Total -->
			<div class="grid border-b sticky top-0 bg-white z-10" :style="gridStyle">
				<div class="p-2 sm:p-3 border-r font-semibold text-xs sm:text-sm">Pracownik</div>
				<div
					v-for="date in weekDates"
					:key="date"
					class="p-1.5 sm:p-2 border-r text-center"
				>
					<div class="font-semibold text-xs sm:text-sm">{{ polishDayName(date) }}</div>
					<div class="text-[10px] sm:text-xs text-gray-500">
						{{ formatDateShort(date) }}
					</div>
				</div>
				<div class="p-1.5 sm:p-2 text-center font-semibold text-xs sm:text-sm">Razem</div>
			</div>

			<!-- Employee rows -->
			<div
				v-for="employee in employees"
				:key="employee.name"
				class="grid border-b hover:bg-gray-50"
				:style="gridStyle"
			>
				<!-- Employee name cell -->
				<div class="p-2 sm:p-3 border-r">
					<div class="font-medium text-xs sm:text-sm truncate">
						{{ employee.employee_name }}
					</div>
					<div class="text-[10px] sm:text-xs text-gray-500 truncate">
						{{ employee.designation }}
					</div>
				</div>

				<!-- Day cells -->
				<CapacityDayCell
					v-for="date in weekDates"
					:key="`${employee.name}-${date}`"
					:cell-data="getCellData(employee.name, date)"
					:employee="employee.name"
					:date="date"
					:readonly="readonly"
					@click="
						!readonly &&
							emit('cell-click', {
								employee: employee.name,
								date,
								employeeName: employee.employee_name,
							})
					"
					@delete-assignment="!readonly && emit('delete-assignment', $event)"
				/>

				<!-- Weekly total cell -->
				<div
					class="p-1.5 sm:p-2 border-l text-center text-xs sm:text-sm font-semibold flex items-center justify-center"
					:class="weekTotalClass(employee.name)"
				>
					{{ weeklyTotal(employee.name).toFixed(1) }}h
				</div>
			</div>
		</div>
	</div>
</template>

<script setup>
import { computed } from "vue";
import CapacityDayCell from "./CapacityDayCell.vue";

const props = defineProps({
	employees: { type: Array, default: () => [] },
	weekDates: { type: Array, default: () => [] },
	plan: { type: Object, default: () => ({}) },
	loading: { type: Boolean, default: false },
	readonly: { type: Boolean, default: false },
});

const emit = defineEmits(["cell-click", "delete-assignment"]);

// Polish day names mapping
const POLISH_DAYS = ["Nd", "Pon", "Wt", "Śr", "Czw", "Pt", "So"];

function polishDayName(date) {
	const d = new Date(date);
	return POLISH_DAYS[d.getDay()];
}

function formatDateShort(date) {
	const d = new Date(date);
	return d.toLocaleDateString("pl-PL", { month: "numeric", day: "numeric" });
}

function getCellData(employee, date) {
	if (props.plan[employee] && props.plan[employee][date]) {
		return props.plan[employee][date];
	}
	return {
		entries: [],
		daily_total: 0,
		is_overbooked: false,
	};
}

function weeklyTotal(employee) {
	let total = 0;
	props.weekDates.forEach((date) => {
		const cell = getCellData(employee, date);
		total += cell.daily_total || 0;
	});
	return total;
}

function weekTotalClass(employee) {
	for (const date of props.weekDates) {
		const cell = getCellData(employee, date);
		if (cell.is_overbooked) {
			return "text-red-700";
		}
	}
	return "text-gray-700";
}

// Responsive grid columns: smaller on mobile
const minGridWidth = computed(() => {
	const dayCount = props.weekDates.length || 5;
	const totalWidth = 140 + dayCount * 120 + 60;
	return totalWidth + "px";
});

const gridStyle = computed(() => {
	const dayCount = props.weekDates.length || 5;
	return {
		gridTemplateColumns: `minmax(120px, 180px) repeat(${dayCount}, minmax(100px, 150px)) 60px`,
	};
});
</script>
